import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function q(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  q("NCLEX-RN","Cardiovascular",3,"A client with left ventricular failure develops frothy pink sputum. The nurse recognizes this as:",["Hemoptysis from pneumonia","Acute pulmonary edema requiring emergent intervention","Normal mucosal secretions","Allergic bronchospasm"],1,"Frothy pink sputum indicates acute pulmonary edema from left ventricular failure. Immediate interventions include high Fowler's position, supplemental oxygen, IV furosemide, IV morphine (with caution), and possible noninvasive positive pressure ventilation."),
  q("NCLEX-RN","Cardiovascular",3,"A client in cardiogenic shock has a MAP of 55 mmHg. The nurse should anticipate:",["Oral antihypertensives","Vasopressor therapy to maintain MAP above 65 mmHg","Fluid restriction only","Outpatient follow-up"],1,"MAP < 65 mmHg indicates inadequate organ perfusion. Vasopressors (norepinephrine, dopamine) are indicated to maintain MAP >= 65 and ensure end-organ perfusion. Cardiogenic shock also requires inotropic support and possibly mechanical circulatory assistance."),
  q("RN-CAT","Cardiovascular",3,"A client with hypertrophic obstructive cardiomyopathy should avoid:",["Rest and relaxation","Valsalva maneuver, dehydration, and sudden standing (reduces preload, worsening obstruction)","Beta-blocker therapy","Adequate hydration"],1,"HCM obstruction worsens with decreased preload or increased contractility. Avoid: Valsalva, dehydration, abrupt standing, strenuous exercise, and vasodilators. Beta-blockers and CCBs are beneficial (reduce contractility and improve filling time)."),
  q("NCLEX-RN","Cardiovascular",3,"After cardioversion for atrial fibrillation, the nurse should first:",["Check the cardiac rhythm on the monitor","Assess the client's airway and level of consciousness","Increase the energy for another attempt","Administer amiodarone IV push"],1,"Post-cardioversion priorities follow ABC: airway management, breathing assessment, circulation check. Verify rhythm conversion on the monitor, assess vital signs, and monitor for complications (embolic events, skin burns, arrhythmias)."),
  q("NCLEX-RN","Cardiovascular",3,"A client with thoracic aortic aneurysm is prescribed strict blood pressure control. The target systolic blood pressure is:",["Below 160 mmHg","Below 120 mmHg to reduce aortic wall stress","Below 140 mmHg","Below 100 mmHg"],1,"Aggressive BP control (SBP < 120 mmHg) reduces aortic wall stress and aneurysm expansion risk. IV beta-blockers (esmolol, labetalol) are first-line to reduce both BP and heart rate (shear stress reduction)."),
  q("NCLEX-RN","Respiratory",3,"A client with community-acquired pneumonia has a respiratory rate of 32 breaths/min and SpO2 of 87% on room air. The nurse should:",["Apply a nasal cannula at 2 L/min and recheck in 1 hour","Apply a high-flow oxygen device to achieve SpO2 above 92%","Wait for ABG results before applying oxygen","Encourage deep breathing exercises only"],1,"SpO2 < 90% requires immediate supplemental oxygen. High-flow devices (non-rebreather mask, Venturi mask) provide higher FiO2 than nasal cannula. Target SpO2 > 92% for most clients; 88-92% for COPD clients to avoid suppressing hypoxic drive."),
  q("NCLEX-RN","Respiratory",3,"A client with a tension pneumothorax presents with tracheal deviation to the opposite side. This is caused by:",["Lung infection pushing the trachea","Mediastinal shift from pressure buildup in the affected hemithorax","Tracheal muscle spasm","Esophageal compression"],1,"Tension pneumothorax causes progressive air accumulation without release, increasing intrapleural pressure. This pushes the mediastinum (including trachea) to the unaffected side, compressing the opposite lung and great vessels, causing cardiovascular collapse."),
  q("RN-CAT","Respiratory",3,"A client on BiPAP has settings of IPAP 14 and EPAP 6. The effective pressure support is:",["14 cmH2O","6 cmH2O","8 cmH2O (difference between IPAP and EPAP)","20 cmH2O"],2,"Pressure support = IPAP - EPAP. IPAP (inspiratory positive airway pressure) assists inspiration; EPAP (expiratory positive airway pressure) maintains alveolar recruitment similar to PEEP. The 8 cmH2O difference is the effective ventilatory support."),
  q("NCLEX-RN","Neurological",3,"A client with a cervical spine injury at C4 will likely require:",["Assistance with ambulation only","Mechanical ventilation due to diaphragm denervation","Upper extremity rehabilitation","No respiratory support"],1,"The phrenic nerve (C3-C5) innervates the diaphragm. C4 injuries impair diaphragmatic function, requiring mechanical ventilation for breathing support. C3 and above injuries almost always require permanent ventilatory support."),
  q("NCLEX-RN","Neurological",3,"A client with an epidural hematoma has a 'lucid interval.' The nurse understands this means:",["Complete recovery has occurred","The client has a brief period of consciousness followed by rapid neurological deterioration","The client will not develop further symptoms","Long-term prognosis is excellent"],1,"Epidural hematomas (usually from middle meningeal artery rupture) classically present with initial loss of consciousness, a lucid interval (temporary improvement), then rapid deterioration from expanding hematoma. This requires emergency craniotomy for clot evacuation."),
  q("RN-CAT","Neurological",3,"A client with trigeminal neuralgia (tic douloureux) reports lancinating facial pain triggered by chewing. First-line medication is:",["Gabapentin","Carbamazepine","Opioid analgesics","NSAIDs"],1,"Carbamazepine is first-line for trigeminal neuralgia, effective in 70-80% of patients. It stabilizes nerve membranes by blocking sodium channels. Monitor CBC (aplastic anemia risk) and sodium (SIADH). Oxcarbazepine is an alternative with fewer drug interactions."),
  q("NCLEX-RN","Endocrine",3,"A client with thyroid storm presents with hyperthermia, tachycardia (180 bpm), and agitation. The priority intervention is:",["Administering levothyroxine","Beta-blockers for heart rate control, followed by antithyroid medications","Radioactive iodine ablation","Providing a high-calorie diet"],1,"Thyroid storm treatment priorities: beta-blocker (propranolol) to control heart rate, PTU or methimazole to block new hormone synthesis, iodine solution (given after PTU) to block hormone release, corticosteroids to inhibit T4-T3 conversion, and supportive care."),
  q("NCLEX-RN","Endocrine",3,"A client with adrenal insufficiency is taught about stress dosing. Which situation requires increased corticosteroid dose?",["Mild headache","Surgical procedure, febrile illness, or trauma","Routine dental cleaning","Normal exercise"],1,"Stress dosing (doubling or tripling the maintenance dose) is required during illness, surgery, trauma, or significant physiological stress because the body needs more cortisol during these times and diseased adrenal glands cannot increase production."),
  q("RN-CAT","Endocrine",3,"A client with type 2 diabetes is being considered for bariatric surgery. The nurse explains that bariatric surgery:",["Has no effect on diabetes","May lead to complete diabetes remission in many patients","Only treats obesity without metabolic effects","Is contraindicated in diabetic patients"],1,"Bariatric surgery (especially Roux-en-Y gastric bypass) achieves T2DM remission in 40-80% of patients, often before significant weight loss occurs. Mechanisms include altered gut hormone secretion, improved insulin sensitivity, and reduced caloric intake."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with a small bowel obstruction has an NG tube to low intermittent suction. The nurse should monitor for:",["Metabolic acidosis","Metabolic alkalosis from loss of gastric acid and potassium","Respiratory alkalosis","No electrolyte changes"],1,"NG suction removes gastric acid (HCl) and potassium, causing metabolic alkalosis and hypokalemia. The nurse monitors ABGs, serum electrolytes, and replaces potassium as ordered. Isotonic IV fluids replace volume losses."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with alcoholic hepatitis has an elevated AST:ALT ratio greater than 2:1. The nurse interprets this as:",["Normal liver function","Suggestive of alcoholic liver disease","Indicative of viral hepatitis","Consistent with hepatocellular carcinoma"],1,"AST:ALT ratio > 2:1 strongly suggests alcoholic liver disease. Alcohol preferentially damages mitochondria (where AST is concentrated). In viral hepatitis, ALT typically exceeds AST. The ratio is a useful diagnostic clue in evaluating liver disease etiology."),
  q("RN-CAT","Gastrointestinal",3,"A client with chronic pancreatitis develops steatorrhea. The nurse should anticipate treatment with:",["Low-fat diet only","Pancreatic enzyme replacement with meals (PERT)","High-protein diet without supplements","Cholestyramine therapy"],1,"Steatorrhea (fatty stools) from chronic pancreatitis indicates pancreatic exocrine insufficiency. PERT (pancrelipase) taken with all meals and snacks replaces deficient lipase, protease, and amylase. Low-fat diet and fat-soluble vitamin supplementation (A, D, E, K) may also be needed."),
  q("NCLEX-RN","Pharmacology",3,"A client on carbamazepine develops Stevens-Johnson syndrome. The nurse recognizes this as:",["A minor drug side effect","A life-threatening immune-mediated skin reaction requiring immediate drug discontinuation","An allergic rash that resolves with antihistamines","A localized contact dermatitis"],1,"SJS/TEN is a severe mucocutaneous reaction causing widespread epidermal necrosis. Mortality is 5-30%. Immediate drug discontinuation, wound care (similar to burns), fluid resuscitation, and possible IVIG are needed. HLA-B*1502 screening reduces risk."),
  q("NCLEX-RN","Pharmacology",3,"A client taking phenytoin has a level of 28 mcg/mL. The nurse should:",["Continue the current dose","Hold the dose and report toxic level to the provider","Increase the dose for better seizure control","Administer a loading dose"],1,"Therapeutic phenytoin level is 10-20 mcg/mL. Level of 28 indicates toxicity causing nystagmus, ataxia, slurred speech, and potentially cardiac arrhythmias. The drug should be held, level monitored serially, and dose adjusted when level returns to range."),
  q("RN-CAT","Pharmacology",3,"A client is receiving a continuous epinephrine infusion. The nurse should monitor closely for:",["Hypokalemia and arrhythmias","Hypoglycemia","Hypothermia","Decreased heart rate"],0,"Epinephrine stimulates beta-2 receptors driving potassium intracellularly (hypokalemia), increases myocardial oxygen demand, and can cause arrhythmias. Continuous ECG monitoring, frequent electrolyte checks, and hemodynamic monitoring are essential."),
  q("NCLEX-RN","Mental Health",3,"A client in the emergency department is experiencing acute alcohol withdrawal with tremors and diaphoresis. The CIWA-Ar score is 22. The nurse should:",["Monitor without medication","Administer benzodiazepines per protocol as CIWA score indicates severe withdrawal","Provide only IV fluids","Discharge with follow-up instructions"],1,"CIWA-Ar score >= 20 indicates severe alcohol withdrawal requiring benzodiazepine therapy (chlordiazepoxide, lorazepam, or diazepam). Untreated severe withdrawal can progress to seizures and delirium tremens with significant mortality."),
  q("NCLEX-RN","Mental Health",3,"A client with schizophrenia has negative symptoms. These include:",["Hallucinations and delusions","Flat affect, alogia, avolition, and social withdrawal","Paranoid ideation","Disorganized speech"],1,"Negative symptoms represent loss of normal function: flat affect (diminished emotional expression), alogia (poverty of speech), avolition (lack of motivation), anhedonia, and social withdrawal. These are more difficult to treat than positive symptoms."),
  q("RN-CAT","Mental Health",4,"A nurse is caring for a client on an involuntary psychiatric hold. The client demands to leave. The nurse should:",["Allow the client to leave immediately","Explain the legal basis for the hold and the client's rights, and notify the treatment team","Physically restrain the client","Ignore the request"],1,"Involuntary holds have legal requirements varying by jurisdiction but generally allow detention for safety evaluation. The nurse explains the legal basis, informs about rights (legal counsel, hearing), and notifies the treatment team. Documentation is essential."),
  q("NCLEX-RN","Pediatrics",3,"A newborn with respiratory distress syndrome has 'ground glass' appearance on chest X-ray. Treatment includes:",["Antibiotic therapy only","Surfactant replacement therapy and CPAP or mechanical ventilation","Chest physiotherapy","High-dose corticosteroids"],1,"RDS (surfactant deficiency in premature neonates) shows diffuse reticulogranular (ground glass) pattern on CXR. Exogenous surfactant instillation through the ETT and respiratory support (CPAP or ventilation) are mainstays. Antenatal steroids prevent RDS."),
  q("NCLEX-RN","Pediatrics",3,"A child with acute glomerulonephritis presents 2 weeks after a streptococcal pharyngitis with:",["Polyuria and polydipsia","Periorbital edema, dark-colored (cola-colored) urine, and hypertension","Projectile vomiting","Severe diarrhea"],1,"Post-streptococcal GN presents 1-3 weeks after GAS infection with periorbital edema (worst in morning), oliguria, cola-colored urine (hematuria), hypertension, and elevated ASO titer. Treatment is supportive; prognosis is generally excellent."),
  q("NCLEX-RN","Pediatrics",3,"A child with suspected abuse has spiral fractures of the humerus. The nurse should:",["Accept the parent's explanation without question","Document findings objectively and report to child protective services","Confront the parent directly about the abuse","Wait for additional injuries before reporting"],1,"Spiral fractures in non-ambulatory children are highly suspicious for abuse. Nurses are mandated reporters. Document findings objectively (description, measurements, photographs with consent), report to CPS, and provide a safe environment for the child."),
  q("NCLEX-RN","Maternal/Newborn",3,"A client in labor with a previous cesarean section wishes for a trial of labor after cesarean (TOLAC). The nurse should ensure:",["No contraindications and continuous fetal monitoring with surgical team available","The client cannot attempt TOLAC under any circumstances","Only intermittent fetal monitoring is needed","The client signs a TOLAC-specific consent without provider discussion"],1,"TOLAC requires: no contraindications (previous classical incision, prior uterine rupture), continuous fetal monitoring, immediate access to operating room and surgical team, and informed consent discussing uterine rupture risk (0.5-1%)."),
  q("NCLEX-RN","Maternal/Newborn",3,"A 2-day-old newborn has a total bilirubin of 19 mg/dL. The nurse should anticipate:",["Continued observation only","Phototherapy and possibly exchange transfusion","Increased oral feeding only","Discharge with follow-up in 1 week"],1,"Total bilirubin of 19 mg/dL in a 2-day-old is significantly elevated and requires phototherapy. Exchange transfusion thresholds depend on gestational age and risk factors. Untreated severe hyperbilirubinemia can cause kernicterus (bilirubin encephalopathy)."),
  q("NCLEX-RN","Renal",3,"A client with nephrotic syndrome has generalized edema and proteinuria > 3.5 g/day. The nurse should anticipate:",["Fluid restriction and high-protein diet","ACEi/ARB therapy, sodium restriction, and albumin replacement if severe","High-sodium diet to replace losses","Unlimited fluid intake"],1,"Nephrotic syndrome management: ACEi/ARB (reduce proteinuria), sodium restriction (< 2g/day), diuretics for edema, statin for hyperlipidemia, and possible IV albumin for severe hypoalbuminemia. Dietary protein should be moderate (0.8-1 g/kg/day)."),
  q("NCLEX-RN","Renal",3,"A client with chronic kidney disease has a potassium of 6.5 mEq/L. Which food should be restricted?",["White rice and pasta","Bananas, oranges, potatoes, and tomatoes","Apples and berries","White bread and crackers"],1,"High-potassium foods include bananas, oranges, potatoes, tomatoes, avocados, dried fruits, nuts, beans, and dairy. CKD patients with hyperkalemia must limit these. Low-potassium alternatives include apples, berries, grapes, and white bread."),
  q("NCLEX-RN","Hematological",3,"A client with hemophilia B (Christmas disease) lacks which clotting factor?",["Factor VIII","Factor IX","Factor VII","Von Willebrand factor"],1,"Hemophilia B (Christmas disease) is deficiency of factor IX. Hemophilia A is factor VIII deficiency. Both are X-linked recessive disorders affecting males. Treatment involves factor replacement therapy. Severity depends on factor level."),
  q("NCLEX-RN","Immunological",3,"A client with systemic lupus erythematosus should be taught to:",["Spend time in direct sunlight for vitamin D production","Avoid sun exposure and use high-SPF sunscreen due to photosensitivity","Increase exercise intensity during flares","Stop medications when feeling well"],1,"SLE photosensitivity causes disease flares with UV exposure. Sunscreen (SPF 30+), protective clothing, and sun avoidance are essential. Other triggers include stress, infection, and certain medications. Medication adherence prevents flares."),
  q("NCLEX-RN","Integumentary",3,"A client with a stage 4 pressure injury has exposed bone at the sacrum. The wound care nurse should:",["Apply a dry gauze dressing and change daily","Implement a multidisciplinary wound care plan including debridement, appropriate dressing, nutrition optimization, and offloading","Pack tightly with iodoform gauze","Apply hydrogen peroxide to the wound bed"],1,"Stage 4 pressure injuries require comprehensive care: wound bed preparation (debridement of necrotic tissue), appropriate moisture-retentive dressings, nutritional optimization (protein, calories, vitamins), pressure redistribution, and possible surgical intervention."),
  q("RN-CAT","Cardiovascular",3,"A client with acute decompensated heart failure is receiving IV nitroglycerin for preload reduction. The nurse monitors for:",["Hyperkalemia","Headache and hypotension (common side effects)","Respiratory depression","Hyperglycemia"],1,"IV nitroglycerin causes venodilation (preload reduction) and at higher doses, arteriodilation (afterload reduction). Common side effects include headache (cerebral vasodilation) and hypotension. Titrate based on symptoms and hemodynamics. Monitor BP continuously."),
  q("RN-CAT","Respiratory",3,"A client with a pulmonary contusion from blunt chest trauma should be monitored for:",["Pneumonia only","Progressive respiratory failure over 24-48 hours as contusion evolves","Immediate improvement","No respiratory complications"],1,"Pulmonary contusion worsens over 24-48 hours as hemorrhage and edema spread through lung parenchyma. Monitor for increasing respiratory distress, deteriorating ABGs, and worsening infiltrates on CXR. May require intubation and lung-protective ventilation."),
  q("NCLEX-RN","Neurological",3,"A client with an ischemic stroke presents within the 4.5-hour treatment window. The nurse should anticipate:",["Anticoagulation with heparin","IV alteplase (tPA) after ruling out hemorrhagic stroke","Surgical intervention first","Observation for 24 hours before treatment"],1,"IV alteplase (tPA) is indicated for ischemic stroke within 4.5 hours of symptom onset. CT scan must first exclude hemorrhagic stroke. BP must be < 185/110 before administration. Strict protocol adherence and close monitoring for bleeding are essential."),
  q("NCLEX-RN","Endocrine",3,"A client with Cushing syndrome being prepared for adrenalectomy should be taught that:",["Cortisol replacement will be temporary only","Lifelong cortisol replacement and stress dosing will be needed","No medication will be needed after surgery","Only mineralocorticoid replacement is needed"],1,"After bilateral adrenalectomy (or unilateral if the remaining gland is suppressed), lifelong glucocorticoid replacement is required. The client must carry emergency identification, understand stress dosing, and know signs of adrenal crisis."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with cirrhosis and hepatic encephalopathy has an ammonia level of 120 mcg/dL. The nurse should anticipate:",["High-protein diet to improve liver function","Lactulose and possible rifaximin to reduce ammonia levels","Dialysis for ammonia removal","IV ammonia infusion"],1,"Lactulose converts ammonia to ammonium in the colon for fecal excretion. Rifaximin reduces ammonia-producing gut bacteria. Dietary protein is restricted during acute episodes but moderate protein is recommended long-term. Target 2-3 soft bowel movements per day."),
  q("NCLEX-RN","Pharmacology",3,"A client on ACE inhibitor therapy who becomes pregnant should:",["Continue the ACE inhibitor throughout pregnancy","Discontinue the ACE inhibitor immediately (teratogenic, especially 2nd-3rd trimester)","Switch to a higher dose","Take the medication every other day"],1,"ACE inhibitors are contraindicated in pregnancy (category D/X). They cause renal dysgenesis, oligohydramnios, and fetal death, especially in 2nd-3rd trimester. Switch to alternative antihypertensives safe in pregnancy (labetalol, nifedipine, methyldopa)."),
  q("NCLEX-RN","Mental Health",3,"Dialectical behavior therapy (DBT) is most effective for clients with:",["Schizophrenia","Borderline personality disorder","Acute psychosis","Cognitive disorders"],1,"DBT was specifically developed for BPD. It combines cognitive-behavioral techniques with mindfulness, teaching four skill modules: mindfulness, interpersonal effectiveness, emotion regulation, and distress tolerance. It reduces self-harm, suicide attempts, and hospitalization."),
  q("NCLEX-RN","Pediatrics",3,"A 12-month-old with febrile seizures should have parents taught that:",["All febrile seizures cause brain damage","Simple febrile seizures are usually benign and do not increase epilepsy risk significantly","Daily anticonvulsant therapy is always required","The child should never have fever again"],1,"Simple febrile seizures (< 15 minutes, generalized, not recurring in 24 hours) are benign in developmentally normal children. Risk of epilepsy is only slightly elevated. Recurrence risk is 30-40%. Parents need fever management education and reassurance."),
  q("NCLEX-RN","Maternal/Newborn",3,"A client with HELLP syndrome develops right upper quadrant pain. The nurse should be concerned about:",["Gallbladder disease","Hepatic hematoma or rupture","Kidney stones","Appendicitis"],1,"HELLP (Hemolysis, Elevated Liver enzymes, Low Platelets) RUQ pain indicates hepatic capsule distension from liver edema or subcapsular hematoma. Hepatic rupture is a life-threatening complication. Immediate delivery is indicated for HELLP syndrome."),
  q("NCLEX-RN","Infection Control",3,"Standard precautions should be used:",["Only for clients with known infectious diseases","For ALL client interactions regardless of known infection status","Only when blood is visible","Only in surgical settings"],1,"Standard precautions apply to ALL patients in ALL settings regardless of suspected or confirmed infection status. They apply to blood, all body fluids (except sweat), non-intact skin, and mucous membranes. Components include hand hygiene, PPE, safe injection practices."),
  q("RN-CAT","Critical Care",4,"A client in the ICU has an intra-aortic balloon pump timed to deflate:",["During systole for afterload reduction","Just before systole (before aortic valve opens) to reduce afterload","During diastole for coronary perfusion","At the end of systole"],1,"IABP deflates just before systole, creating a vacuum effect that reduces aortic pressure and left ventricular afterload, decreasing myocardial oxygen demand. It inflates during diastole to augment coronary perfusion. Proper timing is critical for hemodynamic benefit."),
  q("NCLEX-RN","Cardiovascular",3,"A client with deep vein thrombosis is started on enoxaparin and warfarin simultaneously. The nurse should explain that:",["Both medications should be discontinued after 5 days","Enoxaparin provides immediate anticoagulation while warfarin takes 4-5 days to reach full effect","Warfarin works immediately","The two medications should never be given together"],1,"Warfarin inhibits vitamin K-dependent clotting factor synthesis but takes 4-5 days for full anticoagulant effect. Enoxaparin (LMWH) provides immediate anticoagulation during this overlap period. Enoxaparin is discontinued when INR is therapeutic for 2+ consecutive days."),
  q("NCLEX-RN","Respiratory",3,"A client with pleural effusion has a therapeutic thoracentesis. After the procedure, the nurse should:",["Ambulate the client immediately","Position on the affected side and monitor for pneumothorax","Place the client flat on their back","Encourage vigorous coughing"],1,"Post-thoracentesis: position on the affected side (promotes lung expansion), monitor for pneumothorax (sudden dyspnea, absent breath sounds, chest pain), assess vital signs, and obtain a post-procedure chest X-ray to confirm lung re-expansion."),
  q("NCLEX-RN","Neurological",3,"A client with Parkinson disease is at highest risk for which complication?",["Seizures","Aspiration pneumonia from dysphagia","Hemorrhagic stroke","Hyperthyroidism"],1,"Dysphagia in Parkinson disease increases aspiration risk. Progressive motor impairment affects swallowing coordination. The speech pathologist evaluates swallowing ability, and dietary modifications (thickened liquids, pureed foods) reduce aspiration risk. Aspiration pneumonia is a leading cause of death."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with Clostridium difficile infection should be placed on:",["Standard precautions only","Contact precautions with emphasis on soap and water hand hygiene","Airborne precautions","Droplet precautions"],1,"C. diff requires contact precautions. Critically, SOAP AND WATER hand hygiene is required because alcohol-based sanitizers do NOT kill C. diff spores. Dedicated equipment, enhanced environmental cleaning with sporicidal agents, and antibiotic stewardship are essential."),
  q("NCLEX-RN","Pharmacology",3,"A client starting metformin should be informed about the most common side effects:",["Hypoglycemia and weight gain","GI symptoms including nausea, diarrhea, and abdominal discomfort","Hepatotoxicity","Edema and weight gain"],1,"Metformin causes GI side effects (nausea, diarrhea, abdominal discomfort) in 20-30% of patients. Starting at low dose and titrating slowly, taking with food, and using extended-release formulation reduce GI intolerance. Metformin alone rarely causes hypoglycemia."),
  q("NCLEX-RN","Mental Health",3,"A client with major depression and psychomotor retardation who begins to show increased energy 1-2 weeks after starting an antidepressant should be carefully monitored because:",["The depression is resolving normally","The client may now have sufficient energy to act on suicidal thoughts","The medication is causing mania","Side effects are expected to decrease"],1,"As antidepressants begin working, energy may improve before mood lifts, creating a dangerous window where a suicidal client gains sufficient motivation and energy to act on existing suicidal ideation. Close monitoring and safety precautions are essential during this period."),
  q("NCLEX-RN","Pediatrics",3,"A child with suspected meningitis should have which test performed to confirm the diagnosis?",["Blood culture alone","Lumbar puncture for CSF analysis","CT scan of the head as sole diagnostic test","EEG"],1,"LP with CSF analysis is the definitive diagnostic test for meningitis. CSF is analyzed for cell count, glucose, protein, Gram stain, and culture. CT scan is performed before LP only if signs of elevated ICP, focal neurological deficits, or immunocompromised state."),
  q("NCLEX-RN","Maternal/Newborn",3,"The Bishop score is used to assess:",["Fetal gestational age","Cervical readiness for labor induction","Apgar scoring","Fetal lung maturity"],1,"The Bishop score evaluates cervical readiness: dilation, effacement, station, consistency, and position. Score >= 8 indicates favorable cervix for induction. Score < 6 may require cervical ripening agents (misoprostol, prostaglandin gel, cervical balloon) before oxytocin."),
  q("NCLEX-RN","Renal",3,"A client with acute tubular necrosis has oliguria progressing to anuria. The nurse should anticipate:",["Increased IV fluid administration","Fluid and electrolyte management with possible renal replacement therapy","High-protein diet to support renal recovery","No dietary changes"],1,"ATN oliguric phase management: strict I&O, fluid restriction, dietary potassium and sodium restriction, daily weights, electrolyte monitoring, and possible hemodialysis or CRRT for volume overload, severe hyperkalemia, or uremic symptoms."),
  q("RN-CAT","Hematological",3,"A client receiving massive blood transfusion (> 10 units in 24 hours) should be monitored for:",["Hypernatremia","Hypothermia, hypocalcemia (from citrate toxicity), and coagulopathy","Hyperkalemia only","No additional monitoring beyond standard transfusion protocols"],1,"Massive transfusion complications include hypothermia (cold stored blood), hypocalcemia (citrate binds calcium), dilutional coagulopathy, hyperkalemia, and TRALI. Blood warmers, calcium replacement, monitoring coagulation studies, and 1:1:1 ratios mitigate complications."),
  q("NCLEX-RN","Immunological",3,"A client receiving immunotherapy (checkpoint inhibitor) develops colitis. The nurse should understand that this is:",["A sign of treatment failure","An immune-related adverse event from overactivated immune response","A normal GI finding","Unrelated to the treatment"],1,"Checkpoint inhibitors (pembrolizumab, nivolumab) can cause immune-related adverse events (irAEs) by unleashing the immune system against normal tissues. Colitis, hepatitis, pneumonitis, and endocrinopathies are common. Treatment involves corticosteroids and possible immunotherapy discontinuation."),
  q("NCLEX-RN","Integumentary",3,"A client presents with a wound that has a foul odor and green drainage. This is consistent with:",["Normal wound healing","Pseudomonas aeruginosa infection","Staphylococcal infection","Candida infection"],1,"Pseudomonas aeruginosa produces green-pigmented (pyocyanin) drainage with a characteristically fruity or foul odor. It is commonly found in burn wounds, chronic wounds, and moist environments. Treatment includes anti-pseudomonal antibiotics."),
  q("RN-CAT","Cardiovascular",3,"Takotsubo (stress) cardiomyopathy is differentiated from acute MI by:",["ECG findings","Clean coronary arteries on catheterization with transient apical wall motion abnormalities","Higher troponin levels","Permanent cardiac damage"],1,"Takotsubo mimics acute MI (chest pain, ECG changes, elevated troponin) but coronary arteries are normal. Characteristic apical ballooning on echocardiography is diagnostic. It is triggered by severe emotional or physical stress and typically resolves in weeks."),
  q("RN-CAT","Respiratory",3,"A client with cystic fibrosis develops a pulmonary exacerbation. The nurse should anticipate:",["Oral antibiotics only for 5 days","IV antipseudomonal antibiotics, aggressive airway clearance, and nutritional support","Bronchoscopy as first-line treatment","Discontinuation of all maintenance therapies"],1,"CF exacerbations are often caused by Pseudomonas. Treatment includes IV antipseudomonal antibiotics (tobramycin + ceftazidime), intensified airway clearance (CPT, high-frequency chest wall oscillation), DNase inhalation, and nutritional optimization."),
  q("NCLEX-RN","Neurological",3,"A client with a recent spinal cord injury is at risk for neurogenic shock. Characteristics include:",["Hypertension and tachycardia","Hypotension and bradycardia from loss of sympathetic tone","Fever and leukocytosis","Hyperreflexia"],1,"Neurogenic shock results from sudden loss of sympathetic nervous system tone below the injury. Vasodilation causes hypotension, and unopposed parasympathetic activity causes bradycardia. Treatment: IV fluids, vasopressors, and atropine for symptomatic bradycardia."),
  q("NCLEX-RN","Endocrine",3,"A client with suspected insulinoma has episodes of neuroglycopenia. Whipple triad includes:",["Hyperglycemia, polyuria, and polydipsia","Hypoglycemia symptoms, documented low blood glucose, and symptom relief with glucose administration","Headache, vision changes, and seizures","Weight loss, fatigue, and anorexia"],1,"Whipple triad confirms hypoglycemia-related symptoms: symptoms consistent with hypoglycemia, documented low plasma glucose (< 55 mg/dL), and symptom resolution when glucose is normalized. This triad helps diagnose insulinoma and other causes of pathological hypoglycemia."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with colorectal cancer undergoes an abdominoperineal resection (APR). The nurse should prepare the client for:",["Temporary colostomy that will be reversed","Permanent colostomy because the rectum and anus are removed","No ostomy needed","Ileostomy placement"],1,"APR removes the sigmoid colon, rectum, and anus, creating a permanent end colostomy. The perineal wound requires extensive care. A wound-ostomy-continence nurse is essential for preoperative stoma site marking and postoperative education."),
  q("NCLEX-RN","Pharmacology",3,"A client receiving IV vancomycin develops 'Red Man Syndrome.' The nurse should:",["Stop the infusion permanently","Slow the infusion rate and administer diphenhydramine as ordered","Increase the infusion rate to finish faster","Administer epinephrine"],1,"Red Man Syndrome is a histamine-mediated reaction (not true allergy) to rapid vancomycin infusion. Symptoms include flushing, erythema, and pruritus of the upper body. Slowing the infusion and premedicating with antihistamine prevents recurrence."),
  q("NCLEX-RN","Mental Health",3,"A client with hoarding disorder is receiving cognitive behavioral therapy. The nurse should understand that:",["Forced cleanouts are the most effective intervention","Treatment focuses on decision-making skills, organizational skills, and gradual discarding","Medication alone is sufficient","The client will recover quickly with therapy"],1,"CBT for hoarding addresses distorted beliefs about possessions, improves decision-making and organizational skills, and gradually exposes the client to discarding items. Forced cleanouts without psychological support often worsen symptoms and cause relapse."),
  q("NCLEX-RN","Pediatrics",3,"A child with nephrotic syndrome has generalized edema and massive proteinuria. The nurse should:",["Restrict protein intake severely","Monitor protein intake (moderate, not high), administer prescribed corticosteroids, and assess for infection","Encourage high sodium intake","Administer diuretics as first-line treatment only"],1,"Nephrotic syndrome management: corticosteroids (prednisone is first-line), moderate protein diet, sodium restriction, albumin replacement for severe hypoalbuminemia, diuretics for symptomatic edema, and infection prevention (hypogammaglobulinemia increases risk)."),
  q("NCLEX-RN","Maternal/Newborn",3,"Leopold maneuvers are performed to determine:",["Cervical dilation","Fetal lie, presentation, position, and engagement","Gestational age","Amniotic fluid volume"],1,"Leopold maneuvers are four abdominal palpation techniques: fundal grip (identifies fetal part in fundus), umbilical grip (locates fetal back), Pawlik grip (identifies presenting part), and pelvic grip (assesses engagement and attitude)."),
  q("RN-CAT","Critical Care",4,"A client in the ICU develops ventilator-associated pneumonia. The diagnosis requires:",["Chest X-ray alone","New infiltrate on CXR plus clinical criteria (fever, leukocytosis, purulent sputum) and quantitative cultures","Positive blood cultures only","Clinical symptoms without imaging"],1,"VAP diagnosis combines radiographic (new/progressive infiltrate) and clinical criteria (fever > 38C, leukocytosis, purulent secretions, worsening oxygenation). Quantitative cultures from bronchoalveolar lavage or protected specimen brush confirm the pathogen and guide targeted antibiotic therapy."),
  q("NCLEX-RN","Cardiovascular",3,"A client with peripheral venous disease is taught about leg ulcer care. Venous ulcers typically occur:",["On the toes and dorsum of the foot","Above the medial malleolus with irregular borders and heavy exudate","On the shin with well-defined margins","In the popliteal fossa"],1,"Venous ulcers occur on the medial lower leg (around the medial malleolus) due to venous insufficiency. They have irregular borders, heavy exudate, and surrounding skin changes (lipodermatosclerosis, hemosiderin staining). Compression therapy is the mainstay of treatment."),
  q("NCLEX-RN","Respiratory",3,"A client with a chest tube has the tubing accidentally disconnected. The nurse should first:",["Clamp the chest tube immediately","Submerge the end of the tube in sterile water to create a water seal","Reconnect the tubing without cleaning","Call the provider before taking action"],1,"If a chest tube disconnects, the immediate priority is preventing air entry. Submerging the tube in sterile water (or any clean water) creates a temporary water seal. Do not clamp as this can cause tension pneumothorax. Reconnect with a clean setup as soon as possible."),
  q("NCLEX-RN","Neurological",3,"A client with meningitis has positive Kernig and Brudzinski signs. Kernig sign is tested by:",["Extending the neck while supine","Flexing the hip 90 degrees and then extending the knee (resistance and pain = positive)","Pressing on the abdomen","Dorsiflexing the foot"],1,"Kernig sign: flex the hip 90 degrees with the knee bent, then extend the knee. Resistance and pain in the hamstrings/back = positive. Brudzinski sign: flex the neck; involuntary hip/knee flexion = positive. Both indicate meningeal irritation."),
  q("NCLEX-RN","Endocrine",3,"A client with hypothyroidism is prescribed levothyroxine. The nurse should teach the client to take it:",["At bedtime with a snack","In the morning on an empty stomach, 30-60 minutes before eating","With iron supplements for enhanced absorption","At any time with or without food"],1,"Levothyroxine is best absorbed on an empty stomach. Taking it 30-60 minutes before breakfast optimizes absorption. Calcium, iron, antacids, and fiber supplements should be taken 4 hours apart as they reduce absorption."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with Crohn disease develops a perianal fistula. The nurse should:",["Apply heat packs to the area","Provide sitz baths, meticulous perineal hygiene, and anticipate possible surgical intervention","Restrict all fluids","Apply tight dressings"],1,"Perianal fistulas are common in Crohn disease. Sitz baths provide comfort, meticulous hygiene prevents infection, and non-constipating diet reduces stool irritation. Medical management includes antibiotics (metronidazole, ciprofloxacin) and immunomodulators. Surgical fistulotomy may be needed."),
  q("NCLEX-RN","Pharmacology",3,"When titrating a vasopressor infusion, the nurse should:",["Make large dose adjustments for rapid effect","Titrate in small increments based on MAP goal and reassess hemodynamics frequently","Change doses only when ordered by the physician","Adjust based on urine output alone"],1,"Vasopressor titration requires small, incremental adjustments (typically every 5-15 minutes) based on MAP target (usually >= 65 mmHg), hemodynamic response, and tissue perfusion indicators. Continuous arterial blood pressure monitoring is preferred."),
  q("NCLEX-RN","Maternal/Newborn",3,"A newborn is assessed for neonatal abstinence syndrome (NAS). Scoring tools assess:",["Only respiratory function","Tremors, cry, sleep, feeding, sneezing, and autonomic signs","Weight and length only","Bilirubin levels"],1,"NAS scoring (Finnegan or modified) evaluates CNS hyperirritability (high-pitched cry, tremors, seizures), GI dysfunction (poor feeding, vomiting, diarrhea), and autonomic signs (sneezing, fever, sweating). Scores guide pharmacological and non-pharmacological interventions."),
  q("NCLEX-RN","Renal",3,"A client with renal calculi and ureteral colic is prescribed ketorolac. This is because:",["It is an opioid analgesic","It is an NSAID that reduces renal colic pain through prostaglandin inhibition","It dissolves kidney stones","It acts as a muscle relaxant"],1,"NSAIDs (ketorolac) are effective for renal colic because they reduce renal pelvis pressure by inhibiting prostaglandin-mediated afferent arteriolar vasodilation. They also provide direct analgesic and anti-inflammatory effects. Use cautiously in CKD."),
  q("RN-CAT","Cardiovascular",3,"A client with constrictive pericarditis has a Kussmaul sign. This refers to:",["Paradoxical increase in JVP during inspiration","Alternating strong and weak pulses","Pulsus paradoxus with respiratory variation","Pericardial friction rub"],0,"Kussmaul sign is paradoxical elevation of JVP during inspiration (normally JVP decreases). It indicates inability of the right heart to accommodate increased venous return due to constrictive pericarditis, restrictive cardiomyopathy, or cardiac tamponade."),
  q("RN-CAT","Respiratory",3,"A client with an asthma action plan is in the yellow zone (50-80% of personal best PEFR). The nurse should instruct:",["Continue regular medications only","Use the rescue inhaler and may need to increase controller medication","Go immediately to the emergency department","No medication changes are needed"],1,"Yellow zone (caution): use quick-relief inhaler (albuterol), may need to increase controller medication dose temporarily. If not improving, move to red zone protocol. Helps clients self-manage exacerbations before they become severe."),
  q("NCLEX-RN","Neurological",3,"A client has a positive Babinski sign (upgoing plantar response). In adults, this indicates:",["Normal neurological finding","Upper motor neuron lesion (pathological in adults)","Lower motor neuron disease","Peripheral neuropathy"],1,"Babinski sign (dorsiflexion of the great toe with fanning of other toes upon stroking the lateral sole) is normal in infants up to 12-24 months. In adults, it indicates upper motor neuron damage (corticospinal tract lesion) and warrants neurological investigation."),
  q("NCLEX-RN","Endocrine",3,"A client with diabetic retinopathy should be advised that:",["Annual dilated eye exams are unnecessary once diagnosed","Regular dilated eye examinations and tight glycemic control slow progression","Vision loss is inevitable regardless of treatment","Only laser therapy can address diabetic eye disease"],1,"Diabetic retinopathy progression is slowed by tight glycemic control (HbA1c < 7%), blood pressure control, and lipid management. Annual dilated eye exams detect changes early. Treatment includes laser photocoagulation, anti-VEGF injections, and vitrectomy for advanced disease."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with acute appendicitis should NOT receive:",["IV antibiotics","Laxatives or enemas (risk of perforation)","IV fluids","Pain medication"],1,"Laxatives and enemas increase intraluminal pressure and can cause appendiceal perforation with subsequent peritonitis. Treatment is surgical appendectomy. IV antibiotics are given preoperatively. Pain management should not be withheld as it does not mask diagnosis."),
  q("NCLEX-RN","Pharmacology",3,"A client is prescribed ciprofloxacin. The nurse should instruct the client to avoid:",["All dairy products","Concurrent antacids, iron, and calcium supplements (reduce absorption by chelation)","All fruits and vegetables","Red meat"],1,"Fluoroquinolones chelate with divalent/trivalent cations (calcium, magnesium, iron, aluminum, zinc) in antacids, supplements, and dairy, reducing absorption by up to 90%. Separate administration by 2 hours before or 6 hours after."),
  q("NCLEX-RN","Mental Health",3,"A client with acute dystonia from an antipsychotic medication should receive:",["Additional antipsychotic medication","Benztropine (Cogentin) or diphenhydramine IM for rapid relief","Haloperidol for the movement disorder","Diazepam IV push"],1,"Acute dystonia (sustained muscle contractions causing abnormal postures) is treated with anticholinergic agents: benztropine (Cogentin) 1-2mg IM or diphenhydramine 50mg IM. Relief occurs within minutes. The antipsychotic dose may need adjustment or the medication changed."),
  q("NCLEX-RN","Pediatrics",3,"An infant with pyloric stenosis will have which characteristic metabolic imbalance?",["Metabolic acidosis","Hypochloremic, hypokalemic metabolic alkalosis","Respiratory acidosis","No metabolic abnormalities"],1,"Persistent vomiting in pyloric stenosis causes loss of HCl (hypochloremia), potassium, and hydrogen ions, resulting in metabolic alkalosis. Dehydration and electrolyte imbalances must be corrected BEFORE surgical repair (pyloromyotomy)."),
  q("NCLEX-RN","Renal",3,"A client with an AV fistula for hemodialysis should be taught that:",["Blood pressure measurements should be taken on the fistula arm","No blood pressure measurements, venipunctures, or constriction on the fistula arm","The fistula arm should be kept in a sling at all times","Only trained nurses can assess the fistula"],1,"AV fistula protection: no BP, venipuncture, or IV access on the fistula arm. Avoid constrictive clothing, sleeping on the arm, or carrying heavy objects. Assess for thrill (palpable vibration) and bruit (audible with stethoscope) daily."),
  q("RN-CAT","Critical Care",3,"A client in the ICU has sepsis with a lactate of 4.2 mmol/L. The nurse should understand this indicates:",["Normal metabolic function","Tissue hypoperfusion and anaerobic metabolism requiring aggressive resuscitation","Mild dehydration only","Hepatic dysfunction"],1,"Elevated lactate (> 2 mmol/L) in sepsis indicates tissue hypoperfusion and anaerobic metabolism. Lactate > 4 is associated with high mortality. Aggressive fluid resuscitation, vasopressors, and source control aim to normalize lactate within 6 hours (Surviving Sepsis Campaign target)."),
  q("NCLEX-RN","Cardiovascular",3,"A client with a prosthetic heart valve develops a fever of unknown origin. The nurse should suspect:",["Viral syndrome","Prosthetic valve endocarditis","Medication reaction","Normal post-surgical finding"],1,"Prosthetic valve endocarditis presents with unexplained fever, new murmur, or valve dysfunction. Blood cultures (multiple sets) are critical. Transesophageal echocardiography is more sensitive than TTE for prosthetic valve evaluation. Prolonged IV antibiotics and possible valve replacement are needed."),
  q("NCLEX-RN","Respiratory",3,"A client with COPD develops acute exacerbation. First-line bronchodilator therapy includes:",["Long-acting bronchodilators only","Short-acting beta-agonist (albuterol) plus short-acting anticholinergic (ipratropium)","Inhaled corticosteroids as sole therapy","IV aminophylline as first-line"],1,"COPD exacerbation treatment: SABA (albuterol) + SAAC (ipratropium) via nebulizer or MDI, systemic corticosteroids (prednisone 40mg x 5 days), antibiotics if purulent sputum, and supplemental O2 targeting SpO2 88-92%."),
  q("NCLEX-RN","Neurological",3,"A client with ALS is being evaluated for non-invasive ventilation. The nurse should explain that BiPAP is initiated when:",["The client is in respiratory failure","Respiratory muscle weakness is detected (FVC < 50% predicted or orthopnea symptoms)","The client requests it for comfort only","FVC is normal"],1,"NIV (BiPAP) in ALS improves quality of life and survival when started before respiratory failure. Criteria include FVC < 50% predicted, maximal inspiratory pressure < 60 cmH2O, nocturnal desaturation, or symptoms (orthopnea, morning headaches)."),
  q("NCLEX-RN","Gastrointestinal",3,"A client with hepatitis B has positive HBsAg and HBeAg. The nurse interprets this as:",["Immunity from vaccination","Active infection with high viral replication and infectivity","Past resolved infection","Chronic carrier with low infectivity"],1,"HBsAg positive = active HBV infection. HBeAg positive = high viral replication and high infectivity. This combination indicates the client is highly contagious. Treatment decisions are based on ALT levels, viral load, and liver histology."),
  q("NCLEX-RN","Pharmacology",3,"A client on SSRI therapy develops hyponatremia. The nurse should be aware that SSRIs can cause:",["Diabetes insipidus","SIADH leading to dilutional hyponatremia","Addison disease","Hyperaldosteronism"],1,"SSRIs (particularly in elderly patients) can cause SIADH, leading to dilutional hyponatremia. Symptoms include confusion, fatigue, nausea, and in severe cases, seizures. Sodium levels should be monitored, especially in elderly patients and those on diuretics."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[RN-B1] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
